import { test, expect } from '@playwright/test'
import { searchWith, waitForResults, getResultCount } from './helpers'

test.describe('Ranking Blend', () => {
  test('adjust one ranking blend slider reorders results by blend score @critical @blend', async ({
    page,
  }) => {
    await searchWith(page, {})
    await waitForResults(page)

    // Capture the first result name before blend
    const firstResultBefore = await page
      .locator('[class*="Card"], [data-testid="results-list"] >> text=/\\w/')
      .first()
      .textContent()

    // Open the ranking blend builder and adjust the US News National slider
    const blendBuilder = page.getByTestId('ranking-blend-builder')
    await expect(blendBuilder).toBeVisible()

    const usNewsSlider = blendBuilder
      .locator('[data-field="rank_us_news_national"]')
      .getByRole('slider')
    await usNewsSlider.fill('50')

    // Wait for results to update after blend change
    await waitForResults(page)

    // The URL should now contain the blend parameter
    await expect(page).toHaveURL(/blend=rank_us_news_national:50/)

    // Verify blendScore is being used — the result order should potentially change
    // (we verify the blend param is applied; exact reordering depends on data)
    const resultCount = await getResultCount(page)
    expect(resultCount).toBeGreaterThan(0)
  })

  test('reset blend returns to default sorting @standard @blend', async ({ page }) => {
    // Navigate with an active blend
    await searchWith(page, { blend: 'rank_us_news_national:50,rank_forbes:30' })
    await waitForResults(page)

    // Verify blend is active in URL
    await expect(page).toHaveURL(/blend=/)

    // The Reset button should be visible when blend weights are set
    const blendBuilder = page.getByTestId('ranking-blend-builder')
    const resetButton = blendBuilder.getByRole('button', { name: 'Reset' })
    await expect(resetButton).toBeVisible()

    // Click reset
    await resetButton.click()

    // Wait for results to update
    await waitForResults(page)

    // blend param should be removed from URL
    await expect(page).not.toHaveURL(/blend=/)

    // Reset button should no longer be visible (no weights set)
    await expect(resetButton).toBeHidden()
  })

  test('blend weights reflected in URL query params @comprehensive @blend', async ({ page }) => {
    await searchWith(page, {})
    await waitForResults(page)

    const blendBuilder = page.getByTestId('ranking-blend-builder')

    // Adjust US News National slider to 40
    const usNewsSlider = blendBuilder
      .locator('[data-field="rank_us_news_national"]')
      .getByRole('slider')
    await usNewsSlider.fill('40')

    await expect(page).toHaveURL(/blend=rank_us_news_national:40/)

    // Adjust Forbes slider to 30
    const forbesSlider = blendBuilder
      .locator('[data-field="rank_forbes"]')
      .getByRole('slider')
    await forbesSlider.fill('30')

    // Both weights should appear in the URL
    await expect(page).toHaveURL(/blend=.*rank_us_news_national:40/)
    await expect(page).toHaveURL(/blend=.*rank_forbes:30/)
  })

  test('multiple blend sliders combine correctly with percentages shown @comprehensive @blend', async ({
    page,
  }) => {
    await searchWith(page, { blend: 'rank_us_news_national:40,rank_forbes:60' })
    await waitForResults(page)

    const blendBuilder = page.getByTestId('ranking-blend-builder')

    // US News National: 40 out of 100 total = 40%
    const usNewsField = blendBuilder.locator('[data-field="rank_us_news_national"]')
    await expect(usNewsField.getByText('40 (40%)')).toBeVisible()

    // Forbes: 60 out of 100 total = 60%
    const forbesField = blendBuilder.locator('[data-field="rank_forbes"]')
    await expect(forbesField.getByText('60 (60%)')).toBeVisible()
  })
})

test.describe('Export', () => {
  test('click Export CSV downloads a file @standard @export', async ({ page }) => {
    await searchWith(page, {})
    await waitForResults(page)

    // Set up download listener before clicking
    const downloadPromise = page.waitForEvent('download')

    // Click the Export CSV button
    const csvButton = page.getByRole('button', { name: 'Export CSV' })
    await expect(csvButton).toBeEnabled()
    await csvButton.click()

    // Verify that a download was initiated
    const download = await downloadPromise
    expect(download.suggestedFilename()).toContain('.csv')
  })

  test('click Export PDF downloads a file @standard @export', async ({ page }) => {
    await searchWith(page, {})
    await waitForResults(page)

    // Set up download listener before clicking
    const downloadPromise = page.waitForEvent('download')

    // Click the Export PDF button
    const pdfButton = page.getByRole('button', { name: 'Export PDF' })
    await expect(pdfButton).toBeEnabled()
    await pdfButton.click()

    // Verify that a download was initiated
    const download = await downloadPromise
    expect(download.suggestedFilename()).toContain('college-power-search-export.pdf')
  })

  test('export respects active filters @comprehensive @export', async ({ page }) => {
    // Search with a filter that narrows results
    await searchWith(page, { state: 'MA' })
    await waitForResults(page)

    const filteredCount = await getResultCount(page)
    expect(filteredCount).toBeGreaterThan(0)

    // CSV export: verify the URL includes the filter params
    // The CSV export opens a new tab with /api/export/csv?filters=...
    const [newPage] = await Promise.all([
      page.waitForEvent('popup'),
      page.getByRole('button', { name: 'Export CSV' }).click(),
    ])

    // The export URL should contain the filter data
    const exportUrl = newPage.url()
    expect(exportUrl).toContain('/api/export/csv')
    expect(exportUrl).toContain('filters=')

    // The filters param should include the state filter
    const url = new URL(exportUrl, 'http://localhost:8080')
    const filtersParam = url.searchParams.get('filters')
    expect(filtersParam).toBeTruthy()
    expect(filtersParam).toContain('state')

    await newPage.close()
  })
})

import { type Page, expect } from '@playwright/test'

/**
 * Shared E2E test utilities for Kapow.
 *
 * Tagging convention for test titles:
 *
 *   Tiers (pick one):
 *     @critical        — must-pass smoke tests; blocks deployment
 *     @standard        — normal regression coverage
 *     @comprehensive   — edge cases, visual, slow scenarios
 *
 *   Features (pick one or more):
 *     @search    @filters    @pagination   @sorting
 *     @views     @detail     @columns      @geo
 *     @blend     @export     @auth         @nav
 *     @responsive
 *
 *   Example test title:
 *     'loads search page and displays results @critical @search'
 */

/**
 * Navigate to the /search page with the given URL search params.
 *
 * @example
 *   await searchWith(page, { q: 'MIT', state: 'MA' })
 *   // navigates to /search?q=MIT&state=MA
 */
export async function searchWith(
  page: Page,
  params: Record<string, string>,
): Promise<void> {
  const search = new URLSearchParams(params).toString()
  const url = search ? `/search?${search}` : '/search'
  await page.goto(url)
}

/**
 * Wait for the search results skeleton to clear and results to become visible.
 * Asserts that the loading indicator disappears and at least one result or
 * the "institutions found" / "results" text is visible.
 */
export async function waitForResults(page: Page): Promise<void> {
  // Wait for the loading skeleton to disappear
  await expect(page.getByTestId('results-loading')).toBeHidden({
    timeout: 30_000,
  })

  // Wait for the results summary text to appear
  // Matches both "Showing 1-20 of 42 institutions found" and "100+ results"
  await expect(
    page.getByText(/institutions found|results/i),
  ).toBeVisible({ timeout: 10_000 })
}

/**
 * Parse the displayed result count from the results summary text.
 * Handles both "Showing X-Y of Z institutions found" and "100+ results" formats.
 *
 * @returns The total number of results, or 101 for the "100+" display.
 */
export async function getResultCount(page: Page): Promise<number> {
  const summaryLocator = page.getByText(/Showing \d+/i)
  const text = await summaryLocator.textContent()

  if (!text) {
    throw new Error('Could not find results summary text on page')
  }

  // Match "100+ results" format
  const plusMatch = text.match(/(\d+)\+\s*results/i)
  if (plusMatch) {
    return Number(plusMatch[1]) + 1
  }

  // Match "Showing X-Y of Z institutions found" or "Showing X-Y of Z,ZZZ institutions found"
  const ofMatch = text.match(/of\s+([\d,]+)/i)
  if (ofMatch) {
    return Number(ofMatch[1].replace(/,/g, ''))
  }

  throw new Error(`Could not parse result count from text: "${text}"`)
}

import { test, expect } from '@playwright/test'

test.describe('Landing page', () => {
  test('hero heading and search input are visible @critical @nav', async ({ page }) => {
    await page.goto('/')

    await expect(page.getByRole('heading', { name: 'College Power Search', level: 1 })).toBeVisible()
    await expect(page.getByPlaceholder('Name, location, or major…')).toBeVisible()
  })

  test('submitting a search navigates to /search?q=... @critical @search', async ({ page }) => {
    await page.goto('/')

    await page.getByPlaceholder('Name, location, or major…').fill('MIT')
    await page.getByRole('button', { name: 'Search' }).click()

    await expect(page).toHaveURL('/search?q=MIT')
  })
})

import { test, expect } from '@playwright/test'
import { searchWith, waitForResults, getResultCount } from './helpers'

// ── Critical ────────────────────────────────────────────────────────────────

test.describe('Search & Filters — Critical', () => {
  test('home quicksearch navigates to /search with results visible @critical @search', async ({
    page,
  }) => {
    await page.goto('/')

    // Fill the college name field on the home page
    await page.getByPlaceholder('College name…').fill('University')
    await page.getByRole('button', { name: 'Search' }).click()

    // Should navigate to the search page with the query param
    await expect(page).toHaveURL(/\/search\?q=University/)

    // Results should load
    await waitForResults(page)
    const count = await getResultCount(page)
    expect(count).toBeGreaterThan(0)
  })

  test('apply one filter (state) narrows results @critical @filters', async ({ page }) => {
    // Start with an unfiltered search
    await searchWith(page, {})
    await waitForResults(page)
    const unfilteredCount = await getResultCount(page)

    // Apply a state filter via URL (state is a single-enum ChoiceSearchField)
    await searchWith(page, { state: 'MA' })
    await waitForResults(page)
    const filteredCount = await getResultCount(page)

    // Filtered count should be smaller than unfiltered
    expect(filteredCount).toBeLessThan(unfilteredCount)
    expect(filteredCount).toBeGreaterThan(0)
  })
})

// ── Standard ────────────────────────────────────────────────────────────────

test.describe('Search & Filters — Standard', () => {
  test('single-enum filter (state) narrows results and updates URL @standard @filters', async ({
    page,
  }) => {
    await searchWith(page, {})
    await waitForResults(page)

    // Apply state filter via the sidebar select control
    // The State field is rendered as a <select> (maxSelections === 1)
    const stateSelect = page.locator('label', { has: page.getByText('State') }).locator('select')
    await stateSelect.selectOption('CA')

    // Wait for results to update
    await waitForResults(page)
    const count = await getResultCount(page)
    expect(count).toBeGreaterThan(0)

    // URL should reflect the state filter
    await expect(page).toHaveURL(/[?&]state=CA/)
  })

  test('numeric range filter (enrollment) narrows results @standard @filters', async ({
    page,
  }) => {
    await searchWith(page, {})
    await waitForResults(page)
    const unfilteredCount = await getResultCount(page)

    // Apply enrollment range via URL params (NumericalRangeSearchField)
    await searchWith(page, { enrollment: '1000,5000' })
    await waitForResults(page)
    const filteredCount = await getResultCount(page)

    expect(filteredCount).toBeLessThan(unfilteredCount)
    expect(filteredCount).toBeGreaterThan(0)
  })

  test('full-text filter (fields of study) returns matching institutions @standard @filters', async ({
    page,
  }) => {
    // The fields_of_study field is a TextSearchField
    await searchWith(page, { fields_of_study: 'Biology' })
    await waitForResults(page)
    const count = await getResultCount(page)
    expect(count).toBeGreaterThan(0)
  })

  test('clear one filter widens results back @standard @filters', async ({ page }) => {
    // Start with state filter applied
    await searchWith(page, { state: 'MA' })
    await waitForResults(page)
    const filteredCount = await getResultCount(page)

    // Clear the state filter by selecting "Any" in the dropdown
    const stateSelect = page.locator('label', { has: page.getByText('State') }).locator('select')
    await stateSelect.selectOption('')

    await waitForResults(page)
    const clearedCount = await getResultCount(page)

    // After clearing, results should be wider (more results)
    expect(clearedCount).toBeGreaterThan(filteredCount)
  })

  test('combine two filters from different themes reflects AND combination @standard @filters', async ({
    page,
  }) => {
    // Apply state filter alone
    await searchWith(page, { state: 'CA' })
    await waitForResults(page)
    const stateOnlyCount = await getResultCount(page)

    // Apply state + enrollment range (two different themes: LOCATION + ACADEMICS)
    await searchWith(page, { state: 'CA', enrollment: '1000,10000' })
    await waitForResults(page)
    const combinedCount = await getResultCount(page)

    // Combined filters should return fewer results than state alone
    expect(combinedCount).toBeLessThanOrEqual(stateOnlyCount)
    expect(combinedCount).toBeGreaterThan(0)
  })
})

// ── Comprehensive ───────────────────────────────────────────────────────────

test.describe('Search & Filters — Comprehensive', () => {
  test('filter yielding zero results shows empty state with clear button @comprehensive @filters', async ({
    page,
  }) => {
    // Use a name query that is unlikely to match any institution
    await searchWith(page, { q: 'xyzzyplughnotarealnameever12345' })

    // Wait for loading to finish
    await expect(page.getByTestId('results-loading')).toBeHidden({ timeout: 30_000 })

    // Should show "No colleges match your filters" message
    await expect(page.getByText('No colleges match your filters')).toBeVisible()

    // Should have a "Clear all filters" button
    await expect(page.getByRole('button', { name: 'Clear all filters' })).toBeVisible()
  })

  test('clear all filters returns full result set @comprehensive @filters', async ({ page }) => {
    // Start with a restrictive filter that yields zero results
    await searchWith(page, { q: 'xyzzyplughnotarealnameever12345' })
    await expect(page.getByTestId('results-loading')).toBeHidden({ timeout: 30_000 })
    await expect(page.getByText('No colleges match your filters')).toBeVisible()

    // Click "Clear all filters"
    await page.getByRole('button', { name: 'Clear all filters' }).click()

    // Should return to showing results
    await waitForResults(page)
    const count = await getResultCount(page)
    expect(count).toBeGreaterThan(0)

    // URL should be clean (no filter params)
    await expect(page).toHaveURL('/search')
  })

  test('filter state is reflected in URL query params @comprehensive @filters', async ({
    page,
  }) => {
    await searchWith(page, {})
    await waitForResults(page)

    // Apply state filter via sidebar
    const stateSelect = page.locator('label', { has: page.getByText('State') }).locator('select')
    await stateSelect.selectOption('NY')
    await waitForResults(page)

    // Verify URL contains the state param
    await expect(page).toHaveURL(/[?&]state=NY/)

    // Apply a name filter via the sidebar text input
    const nameInput = page.getByRole('textbox', { name: 'Name' })
    await nameInput.fill('College')

    // Wait for debounced update (400ms debounce + network)
    await page.waitForTimeout(600)
    await waitForResults(page)

    // Both params should be in the URL
    await expect(page).toHaveURL(/[?&]state=NY/)
    await expect(page).toHaveURL(/[?&]name=College/)
  })

  test('rapid filter changes do not cause stale or inconsistent results @comprehensive @filters', async ({
    page,
  }) => {
    await searchWith(page, {})
    await waitForResults(page)

    // Rapidly change state filters
    const stateSelect = page.locator('label', { has: page.getByText('State') }).locator('select')
    await stateSelect.selectOption('CA')
    await stateSelect.selectOption('NY')
    await stateSelect.selectOption('TX')

    // Wait for the final results to settle
    await waitForResults(page)

    // URL should reflect only the last selection
    await expect(page).toHaveURL(/[?&]state=TX/)

    // Results should be valid (not zero unless TX genuinely has zero)
    const count = await getResultCount(page)
    expect(count).toBeGreaterThan(0)
  })
})

import { test, expect } from '@playwright/test'
import { searchWith, waitForResults, getResultCount } from './helpers'

test.describe('Pagination', () => {
  test('result count displayed (Showing X-Y of Z institutions) @critical @pagination', async ({
    page,
  }) => {
    await searchWith(page, {})
    await waitForResults(page)

    // The summary text should match "Showing X–Y of Z institutions found" or "Showing X–Y of Z+ results"
    const summary = page.getByText(/Showing \d+[–-]\d+ of/i)
    await expect(summary).toBeVisible()

    // Verify the count is parseable
    const count = await getResultCount(page)
    expect(count).toBeGreaterThan(0)
  })

  test('click page 2 shows different results and URL updates with page=2 @critical @pagination', async ({
    page,
  }) => {
    await searchWith(page, {})
    await waitForResults(page)

    // Collect first page institution names
    const summaryBefore = await page.getByText(/Showing \d+[–-]\d+ of/i).textContent()

    // Click page 2 in pagination controls
    const paginationControls = page.getByTestId('pagination-controls')
    await expect(paginationControls).toBeVisible()
    await paginationControls.getByRole('button', { name: '2' }).click()

    // Wait for results to update
    await waitForResults(page)

    // URL should contain page=2
    await expect(page).toHaveURL(/[?&]page=2/)

    // Summary text should show a different range (e.g., "Showing 21–40" instead of "Showing 1–20")
    const summaryAfter = await page.getByText(/Showing \d+[–-]\d+ of/i).textContent()
    expect(summaryAfter).not.toBe(summaryBefore)
  })

  test('change page size updates results per page and resets to page 1 @standard @pagination', async ({
    page,
  }) => {
    // Start on page 2 so we can verify reset
    await searchWith(page, { page: '2' })
    await waitForResults(page)

    // Change page size via the "Per page" select
    const pageSizeSelect = page.getByLabel('Per page')
    await pageSizeSelect.selectOption('5')

    // Wait for results to update
    await waitForResults(page)

    // URL should have pageSize=5 and page should be reset (no page param or page=1)
    const url = page.url()
    expect(url).toContain('pageSize=5')
    expect(url).not.toMatch(/[?&]page=/)

    // Summary should show at most 5 results in the range
    const summary = await page.getByText(/Showing \d+[–-]\d+ of/i).textContent()
    expect(summary).not.toBeNull()
    const rangeMatch = summary!.match(/Showing (\d+)[–-](\d+)/)
    expect(rangeMatch).not.toBeNull()
    const rangeSize = Number(rangeMatch![2]) - Number(rangeMatch![1]) + 1
    expect(rangeSize).toBeLessThanOrEqual(5)
  })

  test('pagination controls hidden when all results fit on one page @comprehensive @pagination', async ({
    page,
  }) => {
    // Use a very specific search that returns few results, with a large page size
    await searchWith(page, { q: 'Massachusetts Institute of Technology', pageSize: '100' })
    await waitForResults(page)

    const count = await getResultCount(page)
    if (count <= 100) {
      // Pagination controls should not be visible
      await expect(page.getByTestId('pagination-controls')).toBeHidden()
    } else {
      // If somehow there are more than 100 results, pagination should be visible
      await expect(page.getByTestId('pagination-controls')).toBeVisible()
    }
  })
})

test.describe('Sorting', () => {
  test('click sortable column header in table view reorders results and updates URL @standard @sorting', async ({
    page,
  }) => {
    // Navigate to search in table view
    await searchWith(page, { view: 'table' })
    await waitForResults(page)

    // Click the "Name" sort header
    const sortButton = page.getByTestId('sort-name')
    await expect(sortButton).toBeVisible()
    await sortButton.click()

    // Wait for results to update
    await waitForResults(page)

    // URL should contain sort=name
    await expect(page).toHaveURL(/[?&]sort=name/)
  })

  test('click same header again toggles sort direction ASC to DESC @standard @sorting', async ({
    page,
  }) => {
    // Start with sort=name (ASC by default)
    await searchWith(page, { view: 'table', sort: 'name' })
    await waitForResults(page)

    // Click name header again to toggle to DESC
    const sortButton = page.getByTestId('sort-name')
    await sortButton.click()
    await waitForResults(page)

    // URL should now have sortDir=DESC
    await expect(page).toHaveURL(/[?&]sortDir=DESC/)
    await expect(page).toHaveURL(/[?&]sort=name/)
  })

  test('URL reflects both page number and sort state @comprehensive @sorting @pagination', async ({
    page,
  }) => {
    // Navigate with sort active
    await searchWith(page, { view: 'table', sort: 'name' })
    await waitForResults(page)

    // Click page 2
    const paginationControls = page.getByTestId('pagination-controls')
    await expect(paginationControls).toBeVisible()
    await paginationControls.getByRole('button', { name: '2' }).click()
    await waitForResults(page)

    // URL should contain both sort=name and page=2
    const url = page.url()
    expect(url).toMatch(/[?&]sort=name/)
    expect(url).toMatch(/[?&]page=2/)
  })

  test('sort column headers disabled when ranking blend is active @comprehensive @sorting @blend', async ({
    page,
  }) => {
    // Navigate to table view with a blend weight active
    // The blend param format is "field:weight" (e.g., "admissionRate:50")
    await searchWith(page, { view: 'table', blend: 'admissionRate:50' })
    await waitForResults(page)

    // When blend is active, sort is passed as null — the onSort prop is not provided
    // and header buttons should render without sort interactivity.
    // The sort URL params should not be present (blend clears them).
    const url = page.url()
    expect(url).not.toMatch(/[?&]sort=/)
    expect(url).not.toMatch(/[?&]sortDir=/)
  })
})

import { test, expect } from '@playwright/test'
import { searchWith, waitForResults, getResultCount } from './helpers'

// ── Helpers ─────────────────────────────────────────────────────────────────

/** Click a view mode option in the SegmentedControl (renders as input + label). */
async function switchView(page: import('@playwright/test').Page, mode: string) {
  await page.locator(`input[value="${mode}"] + label`).click()
}

/** Navigate to search and wait for results to load. */
async function searchAndWait(page: import('@playwright/test').Page) {
  await searchWith(page, {})
  await waitForResults(page)
}

// ── Critical tier ───────────────────────────────────────────────────────────

test.describe('Result views and detail modal', () => {
  test('card view renders institution cards with name, city, state @critical @views', async ({
    page,
  }) => {
    await searchAndWait(page)

    // Default view is card — cards are rendered as Mantine Card elements with role="button"
    const cards = page.locator('[class*="mantine-Card-root"][role="button"]')
    await expect(cards.first()).toBeVisible({ timeout: 10_000 })

    const count = await cards.count()
    expect(count).toBeGreaterThan(0)

    // First card should contain institution name (bold text) and city, state
    const firstCard = cards.first()
    const nameText = firstCard.locator('p').first()
    await expect(nameText).not.toBeEmpty()

    // The second <p> holds "city, state" — verify it contains a comma
    const locationText = firstCard.locator('p').nth(1)
    await expect(locationText).toContainText(',')
  })

  test('click institution card opens detail modal with institution name and key metrics @critical @detail', async ({
    page,
  }) => {
    await searchAndWait(page)

    // Click the first card to open the detail modal
    const firstCard = page
      .locator('[class*="mantine-Card-root"][role="button"]')
      .first()
    const institutionName = await firstCard.locator('p').first().textContent()
    expect(institutionName).toBeTruthy()

    await firstCard.click()

    // The modal should open with aria-label "Institution details"
    const modal = page.locator('[role="dialog"][aria-label="Institution details"]')
    await expect(modal).toBeVisible({ timeout: 10_000 })

    // Modal title should contain the institution name
    await expect(modal).toContainText(institutionName!)

    // Key metric sections should be visible: Academics, Cost, Outcomes
    await expect(modal.getByText('Academics')).toBeVisible()
    await expect(modal.getByText('Cost')).toBeVisible()
    await expect(modal.getByText('Outcomes')).toBeVisible()
  })

  // ── Standard tier ───────────────────────────────────────────────────────

  test('switch to list view renders list items with institution data @standard @views', async ({
    page,
  }) => {
    await searchAndWait(page)

    await switchView(page, 'list')

    // List view renders Box elements with role="button" inside a Stack
