test.describe('Geographic Features — Comprehensive', () => {
  test('invalid ZIP code handled gracefully without crash @comprehensive @geo', async ({
    page,
  }) => {
    await searchWith(page, {})
    await waitForResults(page)

    // Try a non-5-digit input
    const zipInput = page.getByLabel('ZIP code')
    await zipInput.fill('abc')
    await page.getByRole('button', { name: 'Go' }).click()

    // Should show a validation error about the format
    await expect(page.getByText(/5-digit ZIP/i)).toBeVisible()

    // The page should not crash — results should still be visible
    await expect(page.getByText(/institutions found|results/i)).toBeVisible()
  })

  test('distance values are reasonable numbers when location is set @comprehensive @geo', async ({
    page,
  }) => {
    // Navigate to search in table view with a location set (Boston area)
    await searchWith(page, {
      userLat: '42.33',
      userLng: '-71.11',
      userState: 'MA',
      view: 'table',
    })
    await waitForResults(page)

    // Table should be visible
    await expect(page.locator('table')).toBeVisible({ timeout: 10_000 })

    // Get all distance cells
    const distanceCells = page.getByTestId('distance')
    const cellCount = await distanceCells.count()
    expect(cellCount).toBeGreaterThan(0)

    // Check each distance value is a reasonable number
    for (let i = 0; i < Math.min(cellCount, 10); i++) {
      const text = await distanceCells.nth(i).textContent()
      expect(text).toBeTruthy()

      // Should match "< 1 mi", "N mi", "N,NNN mi", or em dash for null
      expect(text!.trim()).toMatch(/^(<\s*1\s*mi|\d[\d,]*\s*mi|\u2014)$/)

      // If it's a numeric distance, verify it's reasonable (0-15000 miles)
      const numMatch = text!.match(/^(\d[\d,]*)\s*mi$/)
      if (numMatch) {
        const miles = Number(numMatch[1].replace(/,/g, ''))
        expect(miles).toBeGreaterThanOrEqual(0)
        expect(miles).toBeLessThan(15_000)
      }
    }
  })
})

import { test, expect } from '@playwright/test'
import { searchWith, waitForResults } from './helpers'

/** Switch to table view via SegmentedControl. */
async function switchToTable(page: import('@playwright/test').Page) {
  await page.locator('input[value="table"] + label').click()
  await expect(page.locator('table')).toBeVisible({ timeout: 10_000 })
}

// ── Critical ────────────────────────────────────────────────────────────────

test.describe('Table Column Customization', () => {
  test('table view shows expected default columns @critical @columns', async ({
    page,
  }) => {
    await searchWith(page, {})
    await waitForResults(page)
    await switchToTable(page)

    const table = page.locator('table')

    // Default columns should include Name, City, State
    await expect(table.locator('th').filter({ hasText: 'Name' })).toBeVisible()
    await expect(table.locator('th').filter({ hasText: 'City' })).toBeVisible()
    await expect(
      table.locator('th').filter({ hasText: 'State' }),
    ).toBeVisible()
  })

  // ── Standard ──────────────────────────────────────────────────────────────

  test('uncheck a column in picker removes it from table @standard @columns', async ({
    page,
  }) => {
    await searchWith(page, {})
    await waitForResults(page)
    await switchToTable(page)

    // Verify City column is visible initially
    const table = page.locator('table')
    await expect(table.locator('th').filter({ hasText: 'City' })).toBeVisible()

    // Open the column picker
    await page.getByRole('button', { name: 'Columns' }).click()

    // Uncheck the City checkbox
    const cityCheckbox = page.getByRole('checkbox', { name: 'City' })
    await expect(cityCheckbox).toBeChecked()
    await cityCheckbox.uncheck()

    // City column header should disappear from the table
    await expect(
      table.locator('th').filter({ hasText: 'City' }),
    ).toBeHidden()
  })

  test('re-check a column in picker restores it in table @standard @columns', async ({
    page,
  }) => {
    await searchWith(page, {})
    await waitForResults(page)
    await switchToTable(page)

    // Open the column picker
    await page.getByRole('button', { name: 'Columns' }).click()

    // Uncheck City, then re-check it
    const cityCheckbox = page.getByRole('checkbox', { name: 'City' })
    await cityCheckbox.uncheck()

    const table = page.locator('table')
    await expect(
      table.locator('th').filter({ hasText: 'City' }),
    ).toBeHidden()

    await cityCheckbox.check()

    // City column should reappear
    await expect(table.locator('th').filter({ hasText: 'City' })).toBeVisible()
  })

  // ── Comprehensive ─────────────────────────────────────────────────────────

  test('column visibility persists across page reload via localStorage @comprehensive @columns', async ({
    page,
  }) => {
    await searchWith(page, {})
    await waitForResults(page)
    await switchToTable(page)

    // Open the column picker and uncheck City
    await page.getByRole('button', { name: 'Columns' }).click()
    await page.getByRole('checkbox', { name: 'City' }).uncheck()

    // Verify localStorage was updated
    const storedColumns = await page.evaluate(() =>
      localStorage.getItem('kapow:visible-columns'),
    )
    expect(storedColumns).toBeTruthy()
    expect(storedColumns).not.toContain('city')

    // Close popover by clicking elsewhere, then reload
    await page.locator('body').click({ position: { x: 0, y: 0 } })
    await page.goto('/search?view=table')
    await waitForResults(page)
    await expect(page.locator('table')).toBeVisible({ timeout: 10_000 })

    // City column should still be hidden after reload
    await expect(
      page.locator('table').locator('th').filter({ hasText: 'City' }),
    ).toBeHidden()
  })

  test('column order changes via picker are reflected in table header order @comprehensive @columns', async ({
    page,
  }) => {
    await searchWith(page, {})
    await waitForResults(page)
    await switchToTable(page)

    // Open column picker
    await page.getByRole('button', { name: 'Columns' }).click()

    // Find the first moveable column item and move it down
    const firstOrderItem = page
      .locator('[data-testid^="column-order-item-"]')
      .first()
    const firstLabel = await firstOrderItem.textContent()
    expect(firstLabel).toBeTruthy()

    // Get the label text for comparison
    const moveDownButton = firstOrderItem.getByRole('button', {
      name: /Move .* down/i,
    })

    if (await moveDownButton.isEnabled()) {
      // Get the second item's label before the move
      const secondOrderItem = page
        .locator('[data-testid^="column-order-item-"]')
        .nth(1)
      const secondLabel = await secondOrderItem.textContent()

      await moveDownButton.click()

      // After moving down, the first position should now show the second item
      const newFirstItem = page
        .locator('[data-testid^="column-order-item-"]')
        .first()
      const newFirstLabel = await newFirstItem.textContent()
      expect(newFirstLabel).toContain(secondLabel!.trim())
    }
  })
})

