test.describe('Preferences', () => {
  test('location persists through URL params across page reload @comprehensive @auth', async ({
    page,
  }) => {
    // Set location via URL params (simulates a resolved ZIP code)
    await searchWith(page, {
      userLat: '42.33',
      userLng: '-71.11',
      userState: 'MA',
    })
    await waitForResults(page)

    // Verify location is displayed (Clear location button visible)
    await expect(page.getByLabel('Clear location')).toBeVisible({
      timeout: 10_000,
    })

    // Distance badges should be visible
    const distanceBadges = page.getByTestId('distance')
    await expect(distanceBadges.first()).toBeVisible({ timeout: 10_000 })

    // Copy the URL with location params
    const urlWithLocation = page.url()
    expect(urlWithLocation).toContain('userLat=')
    expect(urlWithLocation).toContain('userLng=')

    // Reload the page with the same URL
    await page.goto(urlWithLocation)
    await waitForResults(page)

    // Location should still be set after reload
    await expect(page.getByLabel('Clear location')).toBeVisible({
      timeout: 10_000,
    })

    // Distance badges should still be visible
    await expect(distanceBadges.first()).toBeVisible({ timeout: 10_000 })
  })
})
